/// Dispatch a list of typed tick pyclasses into a single `pyarrow.Table`.
/// Zero-copy at the pyo3 boundary courtesy of `arrow_pyarrow::IntoPyArrow`;
/// pandas 2.x then aliases the underlying Arrow buffers for all numeric
/// columns.
///
/// # Empty-list behaviour
///
/// * non-empty list -> schema from `arrow_schema_for_qualname(first.qualname)`;
///   mixed-type lists raise `PyRuntimeError`.
/// * empty list + hint -> schema from the hint, zero-row table (pandas /
///   polars still infer dtypes).
/// * empty list + no hint -> zero-column `pyarrow.Table` (public API:
///   see `to_arrow` docstring).
pub(crate) fn pyclass_list_to_arrow_table<'py>(
    py: Python<'py>,
    ticks: &Bound<'py, pyo3::types::PyList>,
    empty_qualname_hint: Option<&str>,
) -> PyResult<Py<PyAny>> {
    let qualname: Option<String> = if ticks.len() == 0 {
        empty_qualname_hint.map(std::string::ToString::to_string)
    } else {
        let first = ticks.get_item(0)?;
        Some(first.get_type().qualname()?.extract()?)
    };
    let Some(qualname) = qualname else {
        // Empty list + no hint -> zero-column Table (documented contract).
        let schema = Arc::new(Schema::empty());
        let batch = RecordBatch::new_empty(schema);
        return record_batch_to_pyarrow_table(py, batch);
    };
    let batch = match qualname.as_str() {
        "CalendarDay" => {
            <CalendarDay as ArrowFromPyclassList>::read_batch(ticks)?
        }
        "EodTick" => {
            <EodTick as ArrowFromPyclassList>::read_batch(ticks)?
        }
        "GreeksTick" => {
            <GreeksTick as ArrowFromPyclassList>::read_batch(ticks)?
        }
        "InterestRateTick" => {
            <InterestRateTick as ArrowFromPyclassList>::read_batch(ticks)?
        }
        "IvTick" => {
            <IvTick as ArrowFromPyclassList>::read_batch(ticks)?
        }
        "MarketValueTick" => {
            <MarketValueTick as ArrowFromPyclassList>::read_batch(ticks)?
        }
        "OhlcTick" => {
            <OhlcTick as ArrowFromPyclassList>::read_batch(ticks)?
        }
        "OpenInterestTick" => {
            <OpenInterestTick as ArrowFromPyclassList>::read_batch(ticks)?
        }
        "OptionContract" => {
            <OptionContract as ArrowFromPyclassList>::read_batch(ticks)?
        }
        "PriceTick" => {
            <PriceTick as ArrowFromPyclassList>::read_batch(ticks)?
        }
        "QuoteTick" => {
            <QuoteTick as ArrowFromPyclassList>::read_batch(ticks)?
        }
        "TradeQuoteTick" => {
            <TradeQuoteTick as ArrowFromPyclassList>::read_batch(ticks)?
        }
        "TradeTick" => {
            <TradeTick as ArrowFromPyclassList>::read_batch(ticks)?
        }
        other => {
            return Err(pyo3::exceptions::PyRuntimeError::new_err(format!(
                "pyclass_list_to_arrow_table: unknown tick type `{other}` -- \
                 expected a value from `thetadatadx`'s typed tick classes"
            )));
        }
    };
    record_batch_to_pyarrow_table(py, batch)
}

/// Zero-copy RecordBatch -> pyarrow.Table via `arrow::pyarrow::IntoPyArrow`
/// on `arrow::pyarrow::Table`. One batch in, one Table out; pyarrow owns
/// the buffers afterwards. The conversion goes through the Arrow C Data
/// Interface -- Rust hands pyarrow an `ArrowArrayStream` FFI pointer and
/// the Python side aliases the underlying buffers in place.
pub(crate) fn record_batch_to_pyarrow_table(py: Python<'_>, batch: RecordBatch) -> PyResult<Py<PyAny>> {
    let schema = batch.schema();
    let table = arrow::pyarrow::Table::try_new(vec![batch], schema)
        .map_err(|e| pyo3::exceptions::PyRuntimeError::new_err(e.to_string()))?;
    let obj = table.into_pyarrow(py)?;
    Ok(obj.unbind())
}
fn read_arrow_batch_from_calendar_day_pyclass_list<'py>(ticks: &Bound<'py, pyo3::types::PyList>) -> PyResult<RecordBatch> {
    let schema = arrow_schema_for_qualname("CalendarDay").expect("generated schema must be present for CalendarDay");
    let n = ticks.len();
    let mut col_date: Vec<i32> = Vec::with_capacity(n);
    let mut col_is_open: Vec<i32> = Vec::with_capacity(n);
    let mut col_open_time: Vec<i32> = Vec::with_capacity(n);
    let mut col_close_time: Vec<i32> = Vec::with_capacity(n);
    let mut col_status: Vec<i32> = Vec::with_capacity(n);
    for i in 0..n {
        let item = ticks.get_item(i)?;
        let typed: pyo3::PyRef<'_, CalendarDay> = item.extract().map_err(|_| {
            pyo3::exceptions::PyRuntimeError::new_err(format!(
                "pyclass_list_to_arrow_table: expected all items to be `CalendarDay`, \
                 got `{}` at index {}", item.get_type().qualname().unwrap_or_else(|_| pyo3::types::PyString::new(ticks.py(), "?")), i
            ))
        })?;
        col_date.push(typed.date);
        col_is_open.push(typed.is_open);
        col_open_time.push(typed.open_time);
        col_close_time.push(typed.close_time);
        col_status.push(typed.status);
    }
    let columns: Vec<ArrayRef> = vec![
        Arc::new(Int32Array::from(col_date)) as ArrayRef,
        Arc::new(Int32Array::from(col_is_open)) as ArrayRef,
        Arc::new(Int32Array::from(col_open_time)) as ArrayRef,
        Arc::new(Int32Array::from(col_close_time)) as ArrayRef,
        Arc::new(Int32Array::from(col_status)) as ArrayRef,
    ];
    RecordBatch::try_new(schema, columns).map_err(|e| pyo3::exceptions::PyRuntimeError::new_err(e.to_string()))
}

